    console.log(`Fetching metadata for ${dataset}.${table}...`);
    const metadataQuery = `
      SELECT 
        COUNT(*) as total_rows,
        SUM(size_bytes) as total_bytes
      FROM \`${dataset}.__TABLES__\`
      WHERE table_id = '${table}'
    `;
    
    const [metadataRows] = await bigquery.query({
      query: metadataQuery,
      location: 'US',
    });
    
    console.log(`Table metadata: ${JSON.stringify(metadataRows)}`);

    // Step 2: Run aggregation queries based on type
    let aggregationResults = {};

    if (aggregationType === 'full' || aggregationType === 'summary') {
      console.log('Running summary aggregation...');
      aggregationResults.summary = await runSummaryAggregation(dataset, table, filters);
    }

    if (aggregationType === 'full' || aggregationType === 'timeseries') {
      console.log('Running time series aggregation...');
      aggregationResults.timeseries = await runTimeSeriesAggregation(dataset, table, filters);
    }

    if (aggregationType === 'full' || aggregationType === 'distribution') {
      console.log('Running distribution aggregation...');
      aggregationResults.distribution = await runDistributionAggregation(dataset, table, filters);
    }

    if (aggregationType === 'full' || aggregationType === 'topn') {
      console.log('Running top-N aggregation...');
      aggregationResults.topN = await runTopNAggregation(dataset, table, filters);
    }

    if (aggregationType === 'full' || aggregationType === 'crossTab') {
      console.log('Running cross-tabulation aggregation...');
      aggregationResults.crossTab = await runCrossTabAggregation(dataset, table, filters);
    }

    // Step 3: Process results in batches if needed
    console.log('Processing aggregated results in batches...');
    const processedResults = await processBatchResults(aggregationResults, batchSize);

    // Step 4: Write aggregated results back to BigQuery
